(()=>{var n=document.querySelector("nav"),d=n.querySelector("ul"),o=document.querySelector("#burger-template").content.cloneNode(!0),t=o.querySelector("button");t.addEventListener("click",()=>{let e=t.getAttribute("aria-expanded")==="false";t.setAttribute("aria-expanded",e)});var r=()=>{t.setAttribute("aria-expanded",!1),t.focus()};n.addEventListener("keyup",e=>{e.code==="Escape"&&r()});document.addEventListener("click",e=>{n.contains(e.target)||r()});n.insertBefore(o,d);window.addEventListener("DOMContentLoaded",()=>{let e=document.querySelector("#toggle");e&&(e.checked=document.documentElement.hasAttribute("dark"),e.addEventListener("change",()=>{document.documentElement.toggleAttribute("dark");let c=document.documentElement.hasAttribute("dark")?"dark":"light";localStorage.setItem("theme",c)}))});})();
